    fn map_empty() {
        assert_eq([].map(|x| x + 1), []);
    }

    global arr_with_100_values: [u32; 100] = [
        42, 123, 87, 93, 48, 80, 50, 5, 104, 84, 70, 47, 119, 66, 71, 121, 3, 29, 42, 118, 2, 54,
