            let expected = BoundedVec::from_array([1, 4, 3, 8]);
            assert_eq(result, expected);
        }

        #[test]
        fn map_preserves_length() {
            let vec: BoundedVec<u32, 4> = BoundedVec::from_array([1, 2, 3, 4]);
            let result = vec.map(|x| x * 2);

